INSERT INTO `home_page` (`id`, `hero_section`, `section`, `created_at`, `updated_at`) VALUES
(1, '{\"hero_title\":\"Find Your Perfect Place..\",\"hero_subtitle\":\"Our intuitive interface allows you to explore a diverse range of locations, each offering unique experiences tailored to your preferences.\",\"hero_photo\":\"find-your-perfect-place-1752572296.jpg\",\"hero_mobile_photo\":\"find-your-perfect-place-1752556573.jpg\"}', '{\"property\":{\"title\":\"Explore Good Places.\",\"subtitle\":\"Unlock the door to adventure and discovery with our curated selection of exceptional destinations. Dive into a world of breathtaking landscapes, vibrant cultures, and unforgettable experiences.\"},\"location\":{\"title\":\"Find By Locations\",\"subtitle\":\"Whether you\'re seeking a cozy caf\\u00e9 in the heart of a bustling metropolis or a hidden gem tucked away in a serene countryside, our platform connects you with the perfect spots tailored to your preferences.\"},\"testimonial\":{\"title\":\"Are You Convenced\",\"subtitle\":\"Experience convenience and value with our carefully curated selection of packages designed to cater to every traveler\'s needs. Whether you\'re planning a romantic getaway, a family vacation, or an adventurous solo expedition\"},\"blog\":{\"title\":\"Our Latest News & Tips\",\"subtitle\":\"Stay informed and inspired with our comprehensive collection of the latest news and insightful tips. From industry updates to expert advice, we\'re dedicated to keeping you ahead of the curve and enhancing your journey.\"}}', '2025-06-13 01:01:39', '2025-07-15 15:08:16');
