(425, '699c56523d96bd3d301540c0', 'https://autods-scraper-images.s3-us-west-2.amazonaws.com/21046621d3a496566288bd910cbe6822.png', '4768370', NULL, 33, 'Factory Wholesale round Square Shovel Head Gardening Farming Construction Shovel with Wood Handle', 'factory-wholesale-round-square-shovel-head-gardening-farming-construction-shovel-with-wood-handle-7b8608', 'new', '2b0f728b-2e23-4d2f-b997-cefaecdf6001', 'Factory Wholesale round Square Shovel Head Gardening Farming Construction Shovel with Wood Handle', NULL, ' Product Description  Specification itemvalueGradeDIYWarranty3 yearsHandle TypeStraightBlade Length9 3/4inCustomized supportOEM, ODM, OBMPlace of OriginChinaHeb...', ' Product Description  Specification itemvalueGradeDIYWarranty3 yearsHandle TypeStraightBlade Length9 3/4inCustomized supportOEM, ODM, OBMPlace of OriginChinaHebeiBrand NameJIAYUANModel Numbe...', '<div> <div><div>Product Description</div></div> <div><div><div><img src=\"https://sc01.alicdn.com/kf/Hef549ccdb1674a1c9dde42f074bbc129y.jpg\"></div><div><img src=\"https://sc01.alicdn.com/kf/Ha206fbb660ce4d0db4ad7a68f0be5e3cN.jpg\"></div><div><img src=\"https://sc01.alicdn.com/kf/H6b9ce057ebd94a2099a2f4333bc738ed5.jpg\"></div></div></div> <div><div>Specification</div></div> <div><div><table><tbody><tr><td><div>item</div></td><td><div>value</div></td></tr><tr><td><div>Grade</div></td><td><div>DIY</div></td></tr><tr><td><div>Warranty</div></td><td><div>3 years</div></td></tr><tr><td><div>Handle Type</div></td><td><div>Straight</div></td></tr><tr><td><div>Blade Length</div></td><td><div>9 3/4in</div></td></tr><tr><td><div>Customized support</div></td><td><div>OEM, ODM, OBM</div></td></tr><tr><td><div>Place of Origin</div></td><td><div>China</div></td></tr><tr><td><div>Hebei</div></td></tr><tr><td><div>Brand Name</div></td><td><div>JIAYUAN</div></td></tr><tr><td><div>Model Number</div></td><td><div>S519-3L</div></td></tr><tr><td><div>Application</div></td><td><div>Garden Shovel</div></td></tr><tr><td><div>Product name</div></td><td><div>Shovel with wood handle</div></td></tr><tr><td><div>Item NO</div></td><td><div>S519-3L</div></td></tr><tr><td><div>Color</div></td><td><div>Customized color</div></td></tr><tr><td><div>Logo</div></td><td><div>Customized Logo</div></td></tr><tr><td><div>Use</div></td><td><div>Hand Toos</div></td></tr><tr><td><div>Customized support</div></td><td><div>OEM, ODM, OBM</div></td></tr></tbody></table></div></div> <div><div>Packing & Delivery</div></div> <div><div>Company Profile</div></div> <div><div><div><div><div><div><div><div>About US</div></div><div><span>My company is the professional hardware manufacturer, which have more than 20 years experiences in this fields. We have more than 20 professional technicians in hardware production. Have advanced production equipment and efficient production capacity fit for demands for difference customers</span><br></div></div></div></div></div></div></div> <div><div><div><div><div><div>TANGSHAN JIAYUAN METALWORK IS A RAPIDLY DEVELOPED TRADING AND PRODUCTION COMPANY, WHICH MAINLY EXPORT STEEL PRODUCTS INCLUDING SCREWS, NAILS AND OTHER HARDWARE.</div></div></div></div></div></div> <div><div>FAQ</div></div> <div><div><div><div><div><div><b>1. who are we?</b><br>We are based in Hebei, China, start from 2024,sell to South America(30.00%),Mid East(30.00%),North America(20.00%),Africa(20.00%). There are total about 11-50 people in our office.<br><br><b>2. how can we guarantee quality?</b><br>Always a pre-production sample before mass production;<br>Always final Inspection before shipment;<br><br><b>3.what can you buy from us?</b><br>NAIL,SCREW,IRON WIRE,WIRE MESH,HAND TOOLS<br><br><b>4. why should you buy from us not from other suppliers?</b><br>null<br><br><b>5. what services can we provide?</b><br>Accepted Delivery Terms: FOB,CFR,CIF,EXW,FCA,DDU；<br>Accepted Payment Currency:USD,EUR,JPY,CAD,AUD,HKD,GBP,CNY,CHF;<br>Accepted Payment Type: T/T,Credit Card,Western Union,Cash;<br>Language Spoken:English,Chinese,Spanish</div></div></div></div></div></div> </div>', 1.37, 0, '1772878024_69abf8c8bb8b9.jpg', NULL, '{\"application\":\"Garden Shovel\",\"blade length\":\"9 3\\/4 in\",\"model number\":\"shovel with wooden handle\",\"brand name\":\"JIAYUAN\",\"place of origin\":\"Hebei, China\",\"customized support\":\"OEM, ODM, OBM\",\"grade\":\"Diy\",\"Bag handle\":\"D-Grip\",\"warranty\":\"3 Years\",\"Product Name\":\"Shovel with wood handle\",\"Color\":\"Customized Color\",\"Logo\":\"Customized Logo\",\"Use\":\"Hand Tools\",\"Customized support\":\"OEM, ODM, OBM\"}', 1, '2026-03-07 15:37:04', '2026-03-07 15:37:05'),
(426, '695ca469943fc9199f09cec5', 'https://autods-scraper-images.s3-us-west-2.amazonaws.com/9e39bdb96144f8d1bf5d3b71a9a7b165.png', '4768370', NULL, 33, 'Ergonomic High-Back Gaming Chair for Adults and Teens, Comfortable Office Desk Chair with 350LBS Capacity, Recliner Racing Style in Purple', 'ergonomic-high-back-gaming-chair-for-adults-and-teens-comfortable-office-desk-chair-with-350lbs-capacity-recliner-racing-style-in-purple-40d130', 'new', 'B09TVSDC5B', 'Ergonomic High-Back Gaming Chair for Adults and Teens, Comfortable Office Desk Chair with 350LBS Capacity, Recliner Racing Style in Purple', NULL, '  Product Description      Ergonomic High-Back Gaming Chair for Adults and Teens  Experience Unmatched Comfort and Support  The Ergonomic High-Back Gaming Chair...', '  Product Description      Ergonomic High-Back Gaming Chair for Adults and Teens  Experience Unmatched Comfort and Support  The Ergonomic High-Back Gaming Chair is designed to provide except...', '<div> <div> <h2>Product Description</h2> <div> <div> <div> <div> <h3> Ergonomic High-Back Gaming Chair for Adults and Teens</h3> <h3> Experience Unmatched Comfort and Support</h3> <p> The Ergonomic High-Back Gaming Chair is designed to provide exceptional comfort and support for both adults and teens. Whether you are gaming for hours or working at your desk, this chair is engineered to enhance your experience. With an adjustable backrest that can recline from 90° to 165°, you can easily find the perfect angle for relaxation or focus. The chair also features adjustable armrests, neck pillows, and lumbar support to ensure that you maintain a comfortable posture throughout your activities.</p> <p> Built with a robust steel frame and a stable five-star base, this chair is capable of supporting up to 350 pounds, making it a reliable choice for users of all sizes. The high-density foam padding ensures long-lasting comfort, while the 360° silent nylon rollers allow for smooth movement across various floor surfaces without causing damage. The stylish purple PU leather finish adds a modern touch to any office or gaming setup, making it not only functional but also visually appealing.</p> </div> </div> <div> <div> <div> <div> <div> <h3>Key Features of the Ergonomic High-Back Gaming Chair</h3> <ul> <li>Adjustable armrests for personalized comfort.</li> <li>Includes adjustable neck and lumbar pillows for enhanced support.</li> <li>High-density foam padding (3.9\") for prolonged sitting comfort.</li> <li>Backrest tilts from 90° to 165° for versatile positioning.</li> <li>Constructed from durable PU leather and a solid steel frame for long-lasting use.</li> </ul> </div> </div> <div> <h4>Product Dimensions</h4> <div><div> <ul> <li><span> <span> Sitting height: 15.7\"-19.7\" </span> </span></li> <li><span> <span> Seat size: 20.5\"*19.3\" </span> </span></li> <li><span> <span> Backrest size: 19.7\"*28.3\" </span> </span></li> <li><span> <span> Height: 44\"—48\" </span> </span></li> </ul> </div></div> </div> </div> </div> </div> </div> </div> </div> </div>', 161.16, 0, '1772879435_69abfe4b89a16.jpg', NULL, '{\"Unit Count\":\"1.0 Count\",\"Room Type\":\"Office\",\"Material\":\"Alloy Steel\",\"Color\":\"Purple\",\"Form Factor\":\"Recliner\",\"Brand\":\"iooHug\",\"Furniture Finish\":\"leather\",\"Back Style\":\"Solid Back\",\"Maximum Weight Recommendation\":\"350 Pounds\",\"Surface Recommendation\":\"Hard Floor\",\"Age Range (Description)\":\"Adult\",\"Recommended Uses For Product\":\"Gaming, Office\",\"Arm Style\":\"With arms\",\"Included Components\":\"Installation Hardware, User Manual\",\"Special Feature\":\"Cushion Availability, Ergonomic, Rolling\",\"Size\":\"27D x 11W x 23H in\"}', 1, '2026-03-07 16:00:35', '2026-03-07 16:00:36'),
