INSERT INTO `theme_setting` (`id`, `site_name`, `favicon`, `header_logo`, `footer_logo`, `address`, `country`, `email`, `primary_phone`, `alt_phone`, `copyright`, `header_menu`, `footer_menu1`, `footer_menu2`, `google_analytics`, `currency`, `currency_position`, `meta_tags`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 'OndjangoBay', 'favicon_1755066002.png', 'header-logo1755066165.png', 'footer-logo1755066165.png', 'SF- 21, Parsvnath Bibhab Plaza, Alpha 1st Commercial Belt, Greater Noida, India', 'India', 'luciacasimiro1992@gmail.com', '+351 910 256 808', '+351 910 256 808', 'Copyright ©️ 2026 All Rights Reserved by OndjangoBay, Lda.', 1, 2, NULL, '<script async src=\"https://www.googletagmanager.com/gtag/js?id=UA-137437974-1\"></script>  <script>    window.dataLayer = window.dataLayer || [];    function gtag(){dataLayer.push(arguments);}    gtag(\'js\', new Date());  </script>', '₹', 'left', '[{\"value\":\"OndjangoBay\"},{\"value\":\"Shop everything you love from trusted sellers in one place. Discover deals\"},{\"value\":\"track your orders\"},{\"value\":\"and enjoy a fast\"},{\"value\":\"secure shopping experience with OndjangoBay.\"}]', '<p data-start=\"600\" data-end=\"880\">OndjangoBay is your all-in-one eCommerce destination designed for a seamless online shopping experience. Whether you’re looking for fashion, electronics, beauty, home essentials, or the latest gadgets — OndjangoBay connects you with verified sellers and exclusive deals every day.</p>\r\n<h3 data-start=\"882\" data-end=\"902\">🔹 Key Features:</h3>\r\n<ul data-start=\"903\" data-end=\"1438\">\r\n<li data-start=\"903\" data-end=\"987\">\r\n<p data-start=\"905\" data-end=\"987\">🛍️ <strong data-start=\"909\" data-end=\"932\">Wide Product Range:</strong> Explore thousands of products across top categories.</p>\r\n</li>\r\n<li data-start=\"988\" data-end=\"1092\">\r\n<p data-start=\"990\" data-end=\"1092\">⚡ <strong data-start=\"992\" data-end=\"1019\">Fast &amp; Secure Checkout:</strong> Safe payments with multiple methods including UPI, cards, and wallets.</p>\r\n</li>\r\n<li data-start=\"1093\" data-end=\"1178\">\r\n<p data-start=\"1095\" data-end=\"1178\">📦 <strong data-start=\"1098\" data-end=\"1123\">Smart Order Tracking:</strong> Get real-time updates on your orders and deliveries.</p>\r\n</li>\r\n<li data-start=\"1179\" data-end=\"1267\">\r\n<p data-start=\"1181\" data-end=\"1267\">❤️ <strong data-start=\"1184\" data-end=\"1209\">Wishlist &amp; Favorites:</strong> Save your favorite items and get notified on discounts.</p>\r\n</li>\r\n<li data-start=\"1268\" data-end=\"1345\">\r\n<p data-start=\"1270\" data-end=\"1345\">💬 <strong data-start=\"1273\" data-end=\"1290\">24×7 Support:</strong> Chat instantly with our support team for quick help.</p>\r\n</li>\r\n<li data-start=\"1346\" data-end=\"1438\">\r\n<p data-start=\"1348\" data-end=\"1438\">🔔 <strong data-start=\"1351\" data-end=\"1382\">Personalized Notifications:</strong> Stay updated on offers, flash sales, and price drops.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1440\" data-end=\"1548\">OndjangoBay makes online shopping easy, fast, and reliable.<br data-start=\"1499\" data-end=\"1502\">\r\nBrowse, compare, and buy — all within seconds!</p>', '2024-08-11 23:36:31', '2026-02-06 11:40:32');
