INSERT INTO `vendor_stores` (`id`, `user_id`, `store_name`, `slug`, `description`, `logo`, `status`, `created_at`, `updated_at`) VALUES
(1, 33, 'ESCX Garment Store', 'escx-garment-store', 'ESCX Garment Store is your go-to destination for stylish, comfortable, and high-quality clothing for all occasions. We offer a curated selection of men’s, women’s, and kids’ apparel, blending contemporary fashion with timeless classics. From casual wear to formal outfits, our collections feature premium fabrics, trend-forward designs, and exceptional craftsmanship. We also stock seasonal specials, accessories, and exclusive pieces you won’t find elsewhere. At ESCX, we believe fashion should be accessible, affordable, and expressive of your unique style. Whether shopping in-store or online, you’ll enjoy excellent customer service, exciting deals, and the perfect outfit for every moment.', '1753088141.jpg', 0, '2025-07-07 04:14:55', '2025-09-22 03:11:08'),
(4, 32, 'Dipanshutech Stores', 'dipanshutech-stores', 'ESCX Garment Store is your go-to destination for stylish, comfortable, and high-quality clothing for all occasions. We offer a curated selection of men’s, women’s, and kids’ apparel, blending contemporary fashion with timeless classics. From casual wear to formal outfits, our collections feature premium fabrics, trend-forward designs, and exceptional craftsmanship. We also stock seasonal specials, accessories, and exclusive pieces you won’t find elsewhere. At ESCX, we believe fashion should be accessible, affordable, and expressive of your unique style. Whether shopping in-store or online, you’ll enjoy excellent customer service, exciting deals, and the perfect outfit for every moment.', '1752040142.png', 1, '2025-07-09 11:19:02', '2025-08-13 11:36:07'),
(5, 33, 'ESCX Electronic Store', 'escx-electronic-store', 'ESCX Garment Store is your go-to destination for stylish, comfortable, and high-quality clothing for all occasions. We offer a curated selection of men’s, women’s, and kids’ apparel, blending contemporary fashion with timeless classics. From casual wear to formal outfits, our collections feature premium fabrics, trend-forward designs, and exceptional craftsmanship. We also stock seasonal specials, accessories, and exclusive pieces you won’t find elsewhere. At ESCX, we believe fashion should be accessible, affordable, and expressive of your unique style. Whether shopping in-store or online, you’ll enjoy excellent customer service, exciting deals, and the perfect outfit for every moment.', '1753083941.jpg', 1, '2025-07-21 13:15:41', '2025-09-06 06:51:25'),
